    "content": "{"content":" * pin_hibernation_swap_type - Pin the swap device for hibernation\n * @device: Block device containing the resume image\n * @offset: Offset identifying the swap area\n *\n * Locate the swap device for @device/@offset and mark it as pinned\n * for hibernation. While pinned, swapoff() is prevented.\n *\n * Only one uswsusp context may pin a swap device at a time.\n * If already pinned, this function returns -EBUSY.\n *\n * Return:\n * >= 0 on success (swap type).\n * -EINVAL if @device is invalid.\n * -ENODEV if the swap device is not found.\n * -EBUSY if the device is already pinned for hibernation.\n */\nint pin_hibernation_swap_type(dev_t device, sector_t offset)\n{\n\tint type;\n\tstruct swap_info_struct *si;\n\n\tspin_lock(&swap_lock);\n\n\ttype = __find_hibernation_swap_type(device, offset);\n\tif (type < 0) {\n\t\tspin_unlock(&swap_lock);\n\t\treturn type;\n\t}\n\n\tsi = swap_type_to_info(type);\n\tif (WARN_ON_ONCE(!si)) {\n\t\tspin_unlock(&swap_lock);\n\t\treturn -ENODEV;\n\t}\n\n\t/*\n\t * hibernate_acquire() prevents concurrent hibernation sessions.\n\t * This check additionally guards against double-pinning within\n\t * the same session.\n\t */\n\tif (WARN_ON_ONCE(si->flags & SWP_HIBERNATION)) {\n\t\tspin_unlock(&swap_lock);\n\t\treturn -EBUSY;\n\t}\n\n\tsi->flags |= SWP_HIBERNATION;\n\n\tspin_unlock(&swap_lock);\n\treturn type;\n}\n\n/**\n * unpin_hibernation_swap_type - Unpin the swap device for hibernation\n * @type: Swap type previously returned by pin_hibernation_swap_type()\n *\n * Clear the hibernation pin on the given swap device, allowing\n * swapoff() to proceed normally.\n *\n * If @type does not refer to a valid swap device, this function\n * does nothing.\n */\nvoid unpin_hibernation_swap_type(int type)\n{\n\tstruct swap_info_struct *si;\n\n\tspin_lock(&swap_lock);\n\tsi = swap_type_to_info(type);\n\tif (!si) {\n\t\tspin_unlock(&swap_lock);\n\t\treturn;\n\t}\n\tsi->flags &= ~SWP_HIBERNATION;\n\tspin_unlock(&swap_lock);\n}\n\n/**\n * find_hibernation_swap_type - Find swap type for hibernation\n * @device: Block device containing the resume image\n * @offset: Offset within the device identifying the swap area\n *\n * Locate the swap device corresponding to @device and @offset.\n *\n * Unlike pin_hibernation_swap_type(), this function only performs a\n * lookup and does not mark the swap device as pinned for hibernation.\n *\n * This is safe in the sysfs-based hibernation path where user space\n * is already frozen and swapoff() cannot run concurrently.\n *\n * Return:\n * A non-negative swap type on success.\n * -EINVAL if @device is invalid.\n * -ENODEV if no matching swap device is found.\n */\nint find_hibernation_swap_type(dev_t device, sector_t offset)\n{\n\tint type;\n\n\tspin_lock(&swap_lock);\n\ttype = __find_hibernation_swap_type(device, offset);\n\tspin_unlock(&swap_lock);\n\n\treturn type;\n}\n\nint find_first_swap(dev_t *device)\n{\n\tint type;\n\n\tspin_lock(&swap_lock);\n\tfor (type = 0; type < nr_swapfiles; type++) {\n\t\tstruct swap_info_struct *sis = swap_info[type];\n\n\t\tif (!(sis->flags & SWP_WRITEOK))\n\t\t\tcontinue;\n\t\t*device = sis->bdev->bd_dev;\n\t\tspin_unlock(&swap_lock);\n\t\treturn type;\n\t}\n\tspin_unlock(&swap_lock);\n\treturn -ENODEV;\n}\n\n/*\n * Get the (PAGE_SIZE) block corresponding to given offset on the swapdev\n * corresponding to given index in swap_info (swap type).\n */\nsector_t swapdev_block(int type, pgoff_t offset)\n{\n\tstruct swap_info_struct *si = swap_type_to_info(type);\n\tstruct swap_extent *se;\n\n\tif (!si || !(si->flags & SWP_WRITEOK))\n\t\treturn 0;\n\tse = offset_to_swap_extent(si, offset);\n\treturn se->start_block + (offset - se->start_page);\n}\n\n/*\n * Return either the total number of swap pages of given type, or the number\n * of free pages of that type (depending on @free)\n *\n * This is needed for software suspend\n */\nunsigned int count_swap_pages(int type, int free)\n{\n\tunsigned int n = 0;\n\n\tspin_lock(&swap_lock);\n\tif ((unsigned int)type < nr_swapfiles) {\n\t\tstruct swap_info_struct *sis = swap_info[type];\n\n\t\tspin_lock(&sis->lock);\n\t\tif (sis->flags & SWP_WRITEOK) {\n\t\t\tn = sis->pages;\n\t\t\tif (free)\n\t\t\t\tn -= swap_usage_in_pages(sis);\n\t\t}\n\t\tspin_unlock(&sis->lock);\n\t}\n\tspin_unlock(&swap_lock);\n\treturn n;\n}\n#endif /* CONFIG_HIBERNATION */\n\nstatic inline int pte_same_as_swp(pte_t pte, pte_t swp_pte)\n{\n\treturn pte_same(pte_swp_clear_flags(pte), swp_pte);\n}\n\n/*\n * No need to decide whether this PTE shares the swap entry with others,\n * just let do_wp_page work it out if a write is requested later - to\n * force COW, vm_page_prot omits write permission from any private vma.\n */\nstatic int unuse_pte(struct vm_area_struct *vma, pmd_t *pmd,\n\t\tunsigned long addr, swp_entry_t entry, struct folio *folio)\n{\n\tstruct page *page;\n\tstruct folio *swapcache;\n\tspinlock_t *ptl;\n\tpte_t *pte, new_pte, old_pte;\n\tbool hwpoisoned = false;\n\tint ret = 1;\n\n\t/*\n\t * If the folio is removed from swap cache by others, continue to\n\t * unuse other PTEs. try_to_unuse may try again if we missed this one.\n\t */\n\tif (!folio_matches_swap_entry(folio, entry))\n\t\treturn 0;\n\n\tswapcache = folio;\n\tfolio = ksm_might_need_to_copy(folio, vma, addr);\n\tif (unlikely(!folio))\n\t\treturn -ENOMEM;\n\telse if (unlikely(folio == ERR_PTR(-EHWPOISON))) {\n\t\thwpoisoned = true;\n\t\tfolio = swapcache;\n\t}\n\n\tpage = folio_file_page(folio, swp_offset(entry));\n\tif (PageHWPoison(page))\n\t\thwpoisoned = true;\n\n\tpte = pte_offset_map_lock(vma->vm_mm, pmd, addr, &ptl);\n\tif (unlikely(!pte || !pte_same_as_swp(ptep_get(pte),\n\t\t\t\t\t\tswp_entry_to_pte(entry)))) {\n\t\tret = 0;\n\t\tgoto out;\n\t}\n\n\told_pte = ptep_get(pte);\n\n\tif (unlikely(hwpoisoned || !folio_test_uptodate(folio))) {\n\t\tswp_entry_t swp_entry;\n\n\t\tdec_mm_counter(vma->vm_mm, MM_SWAPENTS);\n\t\tif (hwpoisoned) {\n\t\t\tswp_entry = make_hwpoison_entry(page);\n\t\t} else {\n\t\t\tswp_entry = make_poisoned_swp_entry();\n\t\t}\n\t\tnew_pte = swp_entry_to_pte(swp_entry);\n\t\tret = 0;\n\t\tgoto setpte;\n\t}\n\n\t/*\n\t * Some architectures may have to restore extra metadata to the page\n\t * when reading from swap. This metadata may be indexed by swap entry\n\t * so this must be called before folio_put_swap().\n\t */\n\tarch_swap_restore(folio_swap(entry, folio), folio);\n\n\tdec_mm_counter(vma->vm_mm, MM_SWAPENTS);\n\tinc_mm_counter(vma->vm_mm, MM_ANONPAGES);\n\tfolio_get(folio);\n\tif (folio == swapcache) {\n\t\trmap_t rmap_flags = RMAP_NONE;\n\n\t\t/*\n\t\t * See do_swap_page(): writeback would be problematic.\n\t\t * However, we do a folio_wait_writeback() just before this\n\t\t * call and have the folio locked.\n\t\t */\n\t\tVM_BUG_ON_FOLIO(folio_test_writeback(folio), folio);\n\t\tif (pte_swp_exclusive(old_pte))\n\t\t\trmap_flags |= RMAP_EXCLUSIVE;\n\t\t/*\n\t\t * We currently only expect small !anon folios, which are either\n\t\t * fully exclusive or fully shared. If we ever get large folios\n\t\t * here, we have to be careful.\n\t\t */\n\t\tif (!folio_test_anon(folio)) {\n\t\t\tVM_WARN_ON_ONCE(folio_test_large(folio));\n\t\t\tVM_WARN_ON_FOLIO(!folio_test_locked(folio), folio);\n\t\t\tfolio_add_new_anon_rmap(folio, vma, addr, rmap_flags);\n\t\t} else {\n\t\t\tfolio_add_anon_rmap_pte(folio, page, vma, addr, rmap_flags);\n\t\t}\n\t} else { /* ksm created a completely new copy */\n\t\tfolio_add_new_anon_rmap(folio, vma, addr, RMAP_EXCLUSIVE);\n\t\tfolio_add_lru_vma(folio, vma);\n\t}\n\tnew_pte = pte_mkold(mk_pte(page, vma->vm_page_prot));\n\tif (pte_swp_soft_dirty(old_pte))\n\t\tnew_pte = pte_mksoft_dirty(new_pte);\n\tif (pte_swp_uffd_wp(old_pte))\n\t\tnew_pte = pte_mkuffd_wp(new_pte);\nsetpte:\n\tset_pte_at(vma->vm_mm, addr, pte, new_pte);\n\tfolio_put_swap(swapcache, folio_file_page(swapcache, swp_offset(entry)));\nout:\n\tif (pte)\n\t\tpte_unmap_unlock(pte, ptl);\n\tif (folio != swapcache) {\n\t\tfolio_unlock(folio);\n\t\tfolio_put(folio);\n\t}\n\treturn ret;\n}\n\nstatic int unuse_pte_range(struct vm_area_struct *vma, pmd_t *pmd,\n\t\t\tunsigned long addr, unsigned long end,\n\t\t\tunsigned int type)\n{\n\tpte_t *pte = NULL;\n\tstruct swap_info_struct *si;\n\n\tsi = swap_info[type];\n\tdo {\n\t\tstruct folio *folio;\n\t\tunsigned long offset;\n\t\tunsigned char swp_count;\n\t\tsoftleaf_t entry;\n\t\tint ret;\n\t\tpte_t ptent;\n\n\t\tif (!pte++) {\n\t\t\tpte = pte_offset_map(pmd, addr);\n\t\t\tif (!pte)\n\t\t\t\tbreak;\n\t\t}\n\n\t\tptent = ptep_get_lockless(pte);\n\t\tentry = softleaf_from_pte(ptent);\n\n\t\tif (!softleaf_is_swap(entry))\n\t\t\tcontinue;\n\t\tif (swp_type(entry) != type)\n\t\t\tcontinue;\n\n\t\toffset = swp_offset(entry);\n\t\tpte_unmap(pte);\n\t\tpte = NULL;\n\n\t\tfolio = swap_cache_get_folio(entry);\n\t\tif (!folio) {\n\t\t\tstruct vm_fault vmf = {\n\t\t\t\t.vma = vma,\n\t\t\t\t.address = addr,\n\t\t\t\t.real_address = addr,\n\t\t\t\t.pmd = pmd,\n\t\t\t};\n\n\t\t\tfolio = swapin_readahead(entry, GFP_HIGHUSER_MOVABLE,\n\t\t\t\t\t\t&vmf);\n\t\t}\n\t\tif (!folio) {\n\t\t\tswp_count = READ_ONCE(si->swap_map[offset]);\n\t\t\tif (swp_count == 0 || swp_count == SWAP_MAP_BAD)\n\t\t\t\tcontinue;\n\t\t\treturn -ENOMEM;\n\t\t}\n\n\t\tfolio_lock(folio);\n\t\tfolio_wait_writeback(folio);\n\t\tret = unuse_pte(vma, pmd, addr, entry, folio);\n\t\tif (ret < 0) {\n\t\t\tfolio_unlock(folio);\n\t\t\tfolio_put(folio);\n\t\t\treturn ret;\n\t\t}\n\n\t\tfolio_free_swap(folio);\n\t\tfolio_unlock(folio);\n\t\tfolio_put(folio);\n\t} while (addr += PAGE_SIZE, addr != end);\n\n\tif (pte)\n\t\tpte_unmap(pte);\n\treturn 0;\n}\n\nstatic inline int unuse_pmd_range(struct vm_area_struct *vma, pud_t *pud,\n\t\t\t\tunsigned long addr, unsigned long end,\n\t\t\t\tunsigned int type)\n{\n\tpmd_t *pmd;\n\tunsigned long next;\n\tint ret;\n\n\tpmd = pmd_offset(pud, addr);\n\tdo {\n\t\tcond_resched();\n\t\tnext = pmd_addr_end(addr, end);\n\t\tret = unuse_pte_range(vma, pmd, addr, next, type);\n\t\tif (ret)\n\t\t\treturn ret;\n\t} while (pmd++, addr = next, addr != end);\n\treturn 0;\n}\n\nstatic inline int unuse_pud_range(struct vm_area_struct *vma, p4d_t *p4d,\n\t\t\t\tunsigned long addr, unsigned long end,\n\t\t\t\tunsigned int type)\n{\n\tpud_t *pud;\n\tunsigned long next;\n\tint ret;\n\n\tpud = pud_offset(p4d, addr);\n\tdo {\n\t\tnext = pud_addr_end(addr, end);\n\t\tif (pud_none_or_clear_bad(pud))\n\t\t\tcontinue;\n\t\tret = unuse_pmd_range(vma, pud, addr, next, type);\n\t\tif (ret)\n\t\t\treturn ret;\n\t} while (pud++, addr = next, addr != end);\n\treturn 0;\n}\n\nstatic inline int unuse_p4d_range(struct vm_area_struct *vma, pgd_t *pgd,\n\t\t\t\tunsigned long addr, unsigned long end,\n\t\t\t\tunsigned int type)\n{\n\tp4d_t *p4d;\n\tunsigned long next;\n\tint ret;\n\n... [Diff truncated. Dropped 1269 lines] ...\n\n\t\tfolio_release_kmap(folio, swap_header);\n\tif (inode)\n\t\tinode_unlock(inode);\n\treturn error;\n}\n\nvoid si_swapinfo(struct sysinfo *val)\n{\n\tunsigned int type;\n\tunsigned long nr_to_be_unused = 0;\n\n\tspin_lock(&swap_lock);\n\tfor (type = 0; type < nr_swapfiles; type++) {\n\t\tstruct swap_info_struct *si = swap_info[type];\n\n\t\tif ((si->flags & SWP_USED) && !(si->flags & SWP_WRITEOK))\n\t\t\tnr_to_be_unused += swap_usage_in_pages(si);\n\t}\n\tval->freeswap = atomic_long_read(&nr_swap_pages) + nr_to_be_unused;\n\tval->totalswap = total_swap_pages + nr_to_be_unused;\n\tspin_unlock(&swap_lock);\n}\n\n/*\n * Verify that nr swap entries are valid and increment their swap map counts.\n *\n * Returns error code in following case.\n * - success -> 0\n * - swp_entry is invalid -> EINVAL\n * - swap-mapped reference is requested but the entry is not used. -> ENOENT\n * - swap-mapped reference requested but needs continued swap count. -> ENOMEM\n */\nstatic int swap_dup_entries(struct swap_info_struct *si,\n\t\t\t    struct swap_cluster_info *ci,\n\t\t\t    unsigned long offset,\n\t\t\t    unsigned char usage, int nr)\n{\n\tint i;\n\tunsigned char count;\n\n\tfor (i = 0; i < nr; i++) {\n\t\tcount = si->swap_map[offset + i];\n\t\t/*\n\t\t * For swapin out, allocator never allocates bad slots. for\n\t\t * swapin, readahead is guarded by swap_entry_swapped.\n\t\t */\n\t\tif (WARN_ON(count == SWAP_MAP_BAD))\n\t\t\treturn -ENOENT;\n\t\t/*\n\t\t * Swap count duplication must be guarded by either swap cache folio (from\n\t\t * folio_dup_swap) or external lock of existing entry (from swap_dup_entry_direct).\n\t\t */\n\t\tif (WARN_ON(!count &&\n\t\t\t    !swp_tb_is_folio(__swap_table_get(ci, offset % SWAPFILE_CLUSTER))))\n\t\t\treturn -ENOENT;\n\t\tif (WARN_ON((count & ~COUNT_CONTINUED) > SWAP_MAP_MAX))\n\t\t\treturn -EINVAL;\n\t}\n\n\tfor (i = 0; i < nr; i++) {\n\t\tcount = si->swap_map[offset + i];\n\t\tif ((count & ~COUNT_CONTINUED) < SWAP_MAP_MAX)\n\t\t\tcount += usage;\n\t\telse if (swap_count_continued(si, offset + i, count))\n\t\t\tcount = COUNT_CONTINUED;\n\t\telse {\n\t\t\t/*\n\t\t\t * Don't need to rollback changes, because if\n\t\t\t * usage == 1, there must be nr == 1.\n\t\t\t */\n\t\t\treturn -ENOMEM;\n\t\t}\n\n\t\tWRITE_ONCE(si->swap_map[offset + i], count);\n\t}\n\n\treturn 0;\n}\n\nstatic int __swap_duplicate(swp_entry_t entry, unsigned char usage, int nr)\n{\n\tint err;\n\tstruct swap_info_struct *si;\n\tstruct swap_cluster_info *ci;\n\tunsigned long offset = swp_offset(entry);\n\n\tsi = swap_entry_to_info(entry);\n\tif (WARN_ON_ONCE(!si)) {\n\t\tpr_err(\"%s%08lx\\n\", Bad_file, entry.val);\n\t\treturn -EINVAL;\n\t}\n\n\tVM_WARN_ON(nr > SWAPFILE_CLUSTER - offset % SWAPFILE_CLUSTER);\n\tci = swap_cluster_lock(si, offset);\n\terr = swap_dup_entries(si, ci, offset, usage, nr);\n\tswap_cluster_unlock(ci);\n\treturn err;\n}\n\n/*\n * swap_dup_entry_direct() - Increase reference count of a swap entry by one.\n * @entry: first swap entry from which we want to increase the refcount.\n *\n * Returns 0 for success, or -ENOMEM if a swap_count_continuation is required\n * but could not be atomically allocated.  Returns 0, just as if it succeeded,\n * if __swap_duplicate() fails for another reason (-EINVAL or -ENOENT), which\n * might occur if a page table entry has got corrupted.\n *\n * Context: Caller must ensure there is no race condition on the reference\n * owner. e.g., locking the PTL of a PTE containing the entry being increased.\n */\nint swap_dup_entry_direct(swp_entry_t entry)\n{\n\tint err = 0;\n\twhile (!err && __swap_duplicate(entry, 1, 1) == -ENOMEM)\n\t\terr = add_swap_count_continuation(entry, GFP_ATOMIC);\n\treturn err;\n}\n\n/*\n * add_swap_count_continuation - called when a swap count is duplicated\n * beyond SWAP_MAP_MAX, it allocates a new page and links that to the entry's\n * page of the original vmalloc'ed swap_map, to hold the continuation count\n * (for that entry and for its neighbouring PAGE_SIZE swap entries).  Called\n * again when count is duplicated beyond SWAP_MAP_MAX * SWAP_CONT_MAX, etc.\n *\n * These continuation pages are seldom referenced: the common paths all work\n * on the original swap_map, only referring to a continuation page when the\n * low \"digit\" of a count is incremented or decremented through SWAP_MAP_MAX.\n *\n * add_swap_count_continuation(, GFP_ATOMIC) can be called while holding\n * page table locks; if it fails, add_swap_count_continuation(, GFP_KERNEL)\n * can be called after dropping locks.\n */\nint add_swap_count_continuation(swp_entry_t entry, gfp_t gfp_mask)\n{\n\tstruct swap_info_struct *si;\n\tstruct swap_cluster_info *ci;\n\tstruct page *head;\n\tstruct page *page;\n\tstruct page *list_page;\n\tpgoff_t offset;\n\tunsigned char count;\n\tint ret = 0;\n\n\t/*\n\t * When debugging, it's easier to use __GFP_ZERO here; but it's better\n\t * for latency not to zero a page while GFP_ATOMIC and holding locks.\n\t */\n\tpage = alloc_page(gfp_mask | __GFP_HIGHMEM);\n\n\tsi = get_swap_device(entry);\n\tif (!si) {\n\t\t/*\n\t\t * An acceptable race has occurred since the failing\n\t\t * __swap_duplicate(): the swap devi