int swsusp_unmark(void)
{
	int error;

	hib_submit_io_sync(REQ_OP_READ, swsusp_resume_block, swsusp_header);
	if (!memcmp(HIBERNATE_SIG,swsusp_header->sig, 10)) {
		memcpy(swsusp_header->sig,swsusp_header->orig_sig, 10);
